import { Component, OnInit } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';
import { Course } from '../../models/course.model';
import { CourseService } from '../../services/course.service';

@Component({
  selector: 'app-course-detail',
  templateUrl: './course-detail.component.html',
  styleUrls: ['./course-detail.component.css'],
})
export class CourseDetailComponent implements OnInit {
  course?: Course;
  loading = true;
  notFound = false;
  enrolled = false;

  constructor(
    private route: ActivatedRoute,
    private router: Router,
    private courseService: CourseService
  ) {}

  ngOnInit(): void {
    const idParam = this.route.snapshot.paramMap.get('id');
    const id = idParam ? Number(idParam) : NaN;

    if (Number.isNaN(id)) {
      this.notFound = true;
      this.loading = false;
      return;
    }

    this.courseService.getCourseById(id).subscribe({
      next: (course) => {
        this.course = course;
        this.notFound = !course;
        this.loading = false;
      },
      error: () => {
        this.notFound = true;
        this.loading = false;
      },
    });
  }

  onEnroll(): void {
    this.enrolled = true;
    // Navigate the student to their profile after enrolling, as
    // required by the routing hands-on.
    setTimeout(() => this.router.navigate(['/profile']), 600);
  }

  goBack(): void {
    this.router.navigate(['/']);
  }
}
<section aria-labelledby="course-detail-heading">
  <button class="btn btn-outline back-btn" (click)="goBack()">&larr; Back to courses</button>

  <app-loading-spinner *ngIf="loading" message="Loading course details..."></app-loading-spinner>

  <p *ngIf="!loading && notFound">Sorry, we couldn't find that course.</p>

  <div class="detail-card" *ngIf="!loading && course">
    <h1 id="course-detail-heading">{{ course.name }}</h1>
    <p class="course-code">{{ course.code }} &middot; {{ course.credits }} credits</p>
    <p class="course-description">{{ course.description }}</p>
    <p *ngIf="course.grade">Current grade: <strong>{{ course.grade }}</strong></p>

    <button class="btn btn-primary" (click)="onEnroll()" [disabled]="enrolled">
      {{ enrolled ? 'Enrolled ✓ redirecting…' : 'Enroll' }}
    </button>
  </div>
</section>
